// t27/rtl_gen/gf32_add.v
// GoldenFloat32 Addition Unit -- [S(1) | E(12) | M(19)], bias 2^(E-1)-1.
// value = (-1)^S (1 + M/2^19) 2^(E-bias).
//
// Generated by test/gen_gf_add_fix.py (generalizes the exhaustively-verified
// gf8_add). Proper float add: significands carry 3 guard bits, alignment captures
// a sticky bit, the post-add leading 1 is found by priority and renormalized, and
// the 19-bit mantissa is rounded to nearest, ties-to-even. The running exponent is
// SIGNED and wide enough to tell underflow (exp<0) from a valid large exponent --
// the previous unit flushed valid exponents >= 2^(E-1) to zero. Verified by
// test/gf_arith_xcheck.py and test/gf_add_sweep.py.

`default_nettype none
module gf32_add (
    input  wire [31:0] a,
    input  wire [31:0] b,
    output reg  [31:0] result
);

    localparam [11:0] EXP_MAX = 12'd4095;
    localparam signed [13:0] EXP_MAX_S = 14'sd4095;

    wire             sign_a = a[31];
    wire [11:0]   exp_a  = a[30:19];
    wire [18:0]   mant_a = a[18:0];
    wire             sign_b = b[31];
    wire [11:0]   exp_b  = b[30:19];
    wire [18:0]   mant_b = b[18:0];

    wire is_zero_a = (exp_a == 12'd0) && (mant_a == 19'd0);
    wire is_zero_b = (exp_b == 12'd0) && (mant_b == 19'd0);
    wire is_inf_a  = (exp_a == EXP_MAX) && (mant_a == 19'd0);
    wire is_inf_b  = (exp_b == EXP_MAX) && (mant_b == 19'd0);
    wire is_nan_a  = (exp_a == EXP_MAX) && (mant_a != 19'd0);
    wire is_nan_b  = (exp_b == EXP_MAX) && (mant_b != 19'd0);

    wire a_larger = (exp_a > exp_b) || ((exp_a == exp_b) && (mant_a >= mant_b));

    reg        big_sign, small_sign, result_sign;
    reg [11:0] big_exp, small_exp;
    reg [18:0] big_m, small_m;
    reg [22:0] big_ext, small_ext, shifted;   // {1, mant, 3 guard bits}
    reg [12:0]  shamt;
    reg            sticky_shift;
    reg [23:0] sum_m;                          // room for add carry
    reg signed [13:0] rexp;
    reg [18:0]  mant_out;
    reg [19:0]   mant_rounded;                    // M+1 bits, catches overflow
    reg            guard, round_b, sticky, round_up;

    always @(*) begin
        big_sign = 0; small_sign = 0; result_sign = 0;
        big_exp = 0; small_exp = 0; big_m = 0; small_m = 0;
        big_ext = 0; small_ext = 0; shifted = 0; shamt = 0; sticky_shift = 0;
        sum_m = 0; rexp = 0; mant_out = 0; mant_rounded = 0;
        guard = 0; round_b = 0; sticky = 0; round_up = 0;

        if (is_nan_a || is_nan_b)
            result = 32'hFFF80001;
        else if (is_inf_a && is_inf_b && (sign_a != sign_b))
            result = 32'hFFF80001;
        else if (is_inf_a)
            result = sign_a ? 32'hFFF80000 : 32'h7FF80000;
        else if (is_inf_b)
            result = sign_b ? 32'hFFF80000 : 32'h7FF80000;
        else if (is_zero_a && is_zero_b)
            result = 32'h0;
        else if (is_zero_a)
            result = b;
        else if (is_zero_b)
            result = a;
        else begin
            if (a_larger) begin
                big_sign = sign_a; big_exp = exp_a; big_m = mant_a;
                small_sign = sign_b; small_exp = exp_b; small_m = mant_b;
            end else begin
                big_sign = sign_b; big_exp = exp_b; big_m = mant_b;
                small_sign = sign_a; small_exp = exp_a; small_m = mant_a;
            end

            big_ext   = {1'b1, big_m,   3'b0};
            small_ext = {1'b1, small_m, 3'b0};
            shamt     = big_exp - small_exp;

            if (shamt >= 23)
                begin shifted = 0; sticky_shift = |small_ext; end
            else begin
                shifted = small_ext >> shamt;
                sticky_shift = |(small_ext & ((23'd1 << shamt) - 23'd1));
            end

            result_sign = big_sign;
            rexp = $signed({2'b0, big_exp});

            if (big_sign == small_sign)
                sum_m = {1'b0, big_ext} + {1'b0, shifted};
            else
                sum_m = {1'b0, big_ext} - {1'b0, shifted};

            if (sum_m == 0) begin
                result = 32'h0;
            end else begin
                if (sum_m[23]) begin
                    rexp = rexp + 14'sd1;
                    mant_out = sum_m[22:4];
                    guard = sum_m[3]; round_b = sum_m[2]; sticky = (|sum_m[1:0]) | sticky_shift;
                end
                else if (sum_m[22]) begin
                    mant_out = sum_m[21:3];
                    guard = sum_m[2]; round_b = sum_m[1]; sticky = (|sum_m[0:0]) | sticky_shift;
                end
                else if (sum_m[21]) begin
                    rexp = rexp - 14'sd1;
                    mant_out = sum_m[20:2];
                    guard = sum_m[1]; round_b = sum_m[0]; sticky = sticky_shift;
                end
                else if (sum_m[20]) begin
                    rexp = rexp - 14'sd2;
                    mant_out = sum_m[19:1];
                    guard = sum_m[0]; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[19]) begin
                    rexp = rexp - 14'sd3;
                    mant_out = sum_m[18:0];
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[18]) begin
                    rexp = rexp - 14'sd4;
                    mant_out = {sum_m[17:0], 1'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[17]) begin
                    rexp = rexp - 14'sd5;
                    mant_out = {sum_m[16:0], 2'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[16]) begin
                    rexp = rexp - 14'sd6;
                    mant_out = {sum_m[15:0], 3'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[15]) begin
                    rexp = rexp - 14'sd7;
                    mant_out = {sum_m[14:0], 4'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[14]) begin
                    rexp = rexp - 14'sd8;
                    mant_out = {sum_m[13:0], 5'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[13]) begin
                    rexp = rexp - 14'sd9;
                    mant_out = {sum_m[12:0], 6'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[12]) begin
                    rexp = rexp - 14'sd10;
                    mant_out = {sum_m[11:0], 7'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[11]) begin
                    rexp = rexp - 14'sd11;
                    mant_out = {sum_m[10:0], 8'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[10]) begin
                    rexp = rexp - 14'sd12;
                    mant_out = {sum_m[9:0], 9'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[9]) begin
                    rexp = rexp - 14'sd13;
                    mant_out = {sum_m[8:0], 10'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[8]) begin
                    rexp = rexp - 14'sd14;
                    mant_out = {sum_m[7:0], 11'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[7]) begin
                    rexp = rexp - 14'sd15;
                    mant_out = {sum_m[6:0], 12'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[6]) begin
                    rexp = rexp - 14'sd16;
                    mant_out = {sum_m[5:0], 13'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[5]) begin
                    rexp = rexp - 14'sd17;
                    mant_out = {sum_m[4:0], 14'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[4]) begin
                    rexp = rexp - 14'sd18;
                    mant_out = {sum_m[3:0], 15'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[3]) begin
                    rexp = rexp - 14'sd19;
                    mant_out = {sum_m[2:0], 16'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[2]) begin
                    rexp = rexp - 14'sd20;
                    mant_out = {sum_m[1:0], 17'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else if (sum_m[1]) begin
                    rexp = rexp - 14'sd21;
                    mant_out = {sum_m[0:0], 18'd0};
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end
                else begin
                    mant_out = 19'd0;
                    guard = 1'b0; round_b = 1'b0; sticky = sticky_shift;
                end

                round_up     = guard && (round_b || sticky || mant_out[0]);
                mant_rounded = {1'b0, mant_out} + (round_up ? 20'd1 : 20'd0);
                if (mant_rounded[19]) begin
                    rexp     = rexp + 14'sd1;
                    mant_out = 19'd0;
                end else begin
                    mant_out = mant_rounded[18:0];
                end

                if (rexp < 0)
                    result = result_sign ? 32'h80000000 : 32'h0;
                else if (rexp >= EXP_MAX_S)
                    result = result_sign ? 32'hFFF80000 : 32'h7FF80000;
                else if (rexp == 0 && mant_out == 19'd0)
                    result = result_sign ? 32'h80000000 : 32'h0;
                else
                    result = {result_sign, rexp[11:0], mant_out};
            end
        end
    end

endmodule
